import { isPlatformBrowser } from '@angular/common';
import {
  ApplicationRef,
  ChangeDetectorRef,
  Component,
  NgZone,
  OnInit,
  PLATFORM_ID,
  Renderer2,
  ViewChild,
  DOCUMENT,
  inject,
} from '@angular/core';
import {
  ActivatedRoute,
  ActivationStart,
  NavigationEnd,
  Router,
  RouterModule,
  RouterOutlet,
} from '@angular/router';
import { environment } from 'src/environments/environment';
import { AuthService } from '../auth/auth.service';
import { FavoritesService } from '../favorites/favorites.service';
import { GlobalService } from '../services/global.service';
import { BuyingService } from '@trokai/shared-data-access';
import { CompletingInformationService } from '../services/completing-information.service';
import { GeolocationService } from '../services/geolocation.service';
import { FooterComponent } from '../footer/footer.component';

import { CookiesDialogComponent } from '../cookies-dialog/cookies-dialog.component';
import { TrokaiGtmService } from '../services/trokai-gtm.service';
import { BrowserRef } from '../services/browser-ref.service';
import { MessagesService } from '@trokai/shared-data-access';
import { NotificationsService } from '@trokai/shared-data-access';
import { MarketingService } from '../services/marketing.service';
import { BreakpointObserver } from '@angular/cdk/layout';
import { AlertService } from '@trokai/shared-ui';
import { LoadingService } from '@trokai/shared-ui';
import { StorageService } from '@trokai/shared-core';

import { HomeService } from '../services/home.service';
import { NavbarComponent } from '../navbar/navbar.component';
import { MatButtonModule } from '@angular/material/button';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatSelectModule } from '@angular/material/select';
import { MatSidenavModule } from '@angular/material/sidenav';
import { SideMenuNav } from '../navbar/side-menu-nav/side-menu-nav.component';
import { DialogService } from '../services/dialog.service';
import { InventoryService } from '../wardrobe/inventory.service';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss'],
  standalone: true,
  imports: [
    NavbarComponent,
    RouterOutlet,
    RouterModule,
    FooterComponent,
    CookiesDialogComponent,
    MatSidenavModule,
    MatFormFieldModule,
    MatSelectModule,
    MatButtonModule,
    SideMenuNav,
  ],
})
export class AppComponent implements OnInit {
  private appRef = inject(ApplicationRef);
  private globalService = inject(GlobalService);
  private favoritesService = inject(FavoritesService);
  private authService = inject(AuthService);
  private router = inject(Router);
  private trokaiGtmService = inject(TrokaiGtmService);
  private completingInformation = inject(CompletingInformationService);
  private browserRef = inject(BrowserRef);
  private buyingService = inject(BuyingService);
  private locationService = inject(GeolocationService);
  private messagesService = inject(MessagesService);
  private notificationsService = inject(NotificationsService);
  private marketingService = inject(MarketingService);
  private inventoryService = inject(InventoryService);
  private bpObserver = inject(BreakpointObserver);
  private alert = inject(AlertService);
  private route = inject(ActivatedRoute);
  private loadingService = inject(LoadingService);
  private homeService = inject(HomeService);
  private renderer = inject(Renderer2);
  private dialogService = inject(DialogService);
  private storage = inject(StorageService);
  private changeDetectorRef = inject(ChangeDetectorRef);
  private ngZone = inject(NgZone);
  private dom = inject(DOCUMENT);
  private platformId = inject(PLATFORM_ID);

  title = 'Trokaí';
  wasLogged = false;
  showCookies = false;

  isMobile = false;

  showHeaderAlert = false;
  headerAlert: string | null = null;

  utmSource!: string;
  openedFromApp = false;

  checkedFirstUrl = false;
  hideNav = false;

  isDEV = environment.production === false;
  _stable = false;

  loadedScripts = false;
  loggedStable = false; // to avoid start micro/macro tasks before the app is stable

  @ViewChild(SideMenuNav) navMobileSide!: SideMenuNav;

  constructor() {
    if (isPlatformBrowser(this.platformId)) {
      /* if micro/macro tasks are started before this check, the app will never be stable
      what would block the hydration and http will always return cache instead of requesting  */
      this.appRef.isStable.subscribe((isStable) => {
        if (isStable) this.onAppStable();

        if (this.isDEV && this._stable !== isStable) {
          this._stable = isStable;
          // console.log('App stability changed:', isStable);
          this.changeDetectorRef.detectChanges();

          if (!isStable) {
            return;

            // 2. Check for pending HTTP or Timers using the browser's native state
            // Angular 17 stores pending tasks here:
            const pendingTasks = (this.appRef as any)._pendingTasks;
            console.log('Pending Tasks Count:', pendingTasks);

            // 3. Inspect the Zone's private state for rogue timers
            const taskState = (this.ngZone as any)._inner?._zoneDelegate
              ?._taskCounts;
            console.log('Zone Task Counts:', taskState);
            // Look for: macroTask > 0 (Timers) or microTask > 0 (Promises)
          }
        }
      });

      // Check if mobile — run outside zone to avoid keeping app unstable
      this.ngZone.runOutsideAngular(() => {
        this.bpObserver.observe('(max-width: 600px)').subscribe((result) => {
          this.ngZone.run(() => (this.isMobile = result.matches));
        });
      });
    }
    this.globalService.load();
  }

  isStable() {
    return this._stable;
  }

  ngOnInit(): void {
    if (!isPlatformBrowser(this.platformId)) return;

    this.router.events.subscribe((ev) => {
      // Disable dialogs on some routes (postage label)
      if (ev instanceof ActivationStart) {
        this.hideNav = ev.snapshot.data && ev.snapshot.data.hideNav;
      }

      if (ev instanceof NavigationEnd) {
        let url = this.router.url.split('?')[0];
        if (url === '/') url = '';

        this.utmSource = this.route.snapshot.queryParams['utm_source'];
        this.openedFromApp = this.utmSource === 'app';

        if (!this.checkedFirstUrl) {
          this.checkDialogs();
          this.checkedFirstUrl = true;
        }

        this.updateCanonicalUrl(environment.domain + url);
        this.marketingService.resetScroll();
        this.showHeaderAlert = this.router.url === '/';
      }
    });

    this.authService.logged.subscribe((logged) => {
      if (!logged && this.wasLogged) this.onLogout();
      if (logged) this.onLogin();
      this.wasLogged = !!logged;
    });

    this.authService.autoLogin();
    this.buyingService.loadBasketsStorage();

    this.homeService.homeAlert$.subscribe((alert) =>
      // Run outside zone — this 0ms timeout would create a pending Zone.js
      // macrotask on every homeAlert$ emission and delay app stabilization.
      this.ngZone.runOutsideAngular(() =>
        setTimeout(() =>
          this.ngZone.run(() => (this.headerAlert = alert ?? null)),
        ),
      ),
    );
  }

  async checkDialogs() {
    if (this.openedFromApp || this.hideNav) return;

    if (this.route.snapshot.queryParams['coupon']) {
      this.marketingService.checkCoupon(
        this.route.snapshot.queryParams['coupon'],
      );
      return;
    }

    this.showCookies = !(await this.storage.has('accepted_cookies'));
    if (!this.isMobile || this.showCookies) return;

    this.dialogService.openOpenAppDialog(this.router.url.substring(1));
  }

  updateCanonicalUrl(url: string) {
    const head = this.dom.getElementsByTagName('head')[0];
    let element: HTMLLinkElement | null =
      this.dom.querySelector(`link[rel='canonical']`) || null;
    if (element == null) {
      element = this.dom.createElement('link') as HTMLLinkElement;
      head.appendChild(element);
    }
    element.setAttribute('rel', 'canonical');
    element.setAttribute('href', url);
  }

  async onLogin() {
    this.favoritesService.fetchFavorites().subscribe();
    this.locationService.reset();

    await this.buyingService.getMyReserves();
    this.trokaiGtmService.identifyUser(); // push user data to GTM
    this.completingInformation.next();
  }

  async onAppStable() {
    if (this.authService.isLogged() && !this.loggedStable) {
      this.loggedStable = true;
      this.completingInformation.restoreAction(); // user logou navegando (google) ou recarregou a página
      this.notificationsService.fetchUnreadCount();
      this.messagesService.fetchChats();
    }

    if (environment.production && !this.loadedScripts) {
      this.loadedScripts = true;
      this.browserRef.loadMainScripts();
      this.trokaiGtmService.addGtmToDom();
    }
  }

  async onLogout() {
    this.loggedStable = false;
    this.authService.redirectToLogin();
    this.favoritesService.reset();
    this.buyingService.reset();
    this.completingInformation.reset();
    this.locationService.reset();
    this.messagesService.reset();
    this.notificationsService.reset();
    this.trokaiGtmService.logoutEvent();
    this.inventoryService.reset();
  }

  async checkEmailVerify() {
    try {
      const params = this.route.snapshot.queryParams;
      if (!params || !params['email-verify']) return;
      if (!params['email'] || !params['code']) return;

      await this.globalService.verifyEmail(
        params['email'],
        params['code'].toString(),
      );

      this.alert.showDialog(
        'Email verificado com sucesso!',
        'Você já pode utilizar o Trokaí normalmente.',
      );
      this.router.navigate(['/']);
    } catch {
      this.router.navigate(['/']);
    }
  }

  onDrawerClosed() {
    const container = this.dom.querySelector('mat-drawer-container');
    if (container) {
      this.renderer.removeStyle(container, 'overflow');
      this.renderer.removeStyle(container, 'height');
      this.navMobileSide.menuTab = null;
    }
  }

  onDrawerOpened() {
    // set body overflow hidden
    const container = this.dom.querySelector('mat-drawer-container');
    if (container) {
      this.renderer.setStyle(container, 'overflow', 'hidden');
      this.renderer.setStyle(container, 'height', '100dvh'); // Ensure it takes full screen height
    }
  }

  onAcceptCookies() {
    this.showCookies = false;
  }
}

import {
  Address,
  AppleResponse,
  AuthResponseData,
  AuthSessionData,
  StorageService,
  User,
} from '@trokai/shared-core';
import { UserService } from '@trokai/shared-data-access';
import { AlertService } from '@trokai/shared-ui';
import { Router } from '@angular/router';
import { isPlatformBrowser } from '@angular/common';
import { HttpClient } from '@angular/common/http';
import { Injectable, PLATFORM_ID, inject } from '@angular/core';
import { OAuthService } from 'angular-oauth2-oidc';
import { BehaviorSubject, lastValueFrom, Subject } from 'rxjs';
import { environment } from '../../environments/environment';
import { BrowserRef } from '../services/browser-ref.service';

declare const AppleID: any;

@Injectable({
  providedIn: 'root',
})
export class AuthService {
  private http = inject(HttpClient);
  private userService = inject(UserService);
  private alert = inject(AlertService);
  private router = inject(Router);
  private oAuthService = inject(OAuthService);
  private browserRef = inject(BrowserRef);
  private storage = inject(StorageService);
  private platformId = inject(PLATFORM_ID);

  private _user = new BehaviorSubject<User | undefined>(undefined); // atualiza os objetos de usuario
  private _logged = new BehaviorSubject<boolean | undefined>(undefined); // atualiza o usuario apenas login/logout

  public addressUpdated$ = new Subject<void>();

  hasPassword: boolean | null = null;

  get logged() {
    return this._logged.asObservable();
  }

  get user() {
    return this._user.asObservable();
  }

  constructor() {
    if (isPlatformBrowser(this.platformId)) {
      this.oAuthService.configure({
        issuer: 'https://accounts.google.com',
        strictDiscoveryDocumentValidation: false,
        redirectUri: this.browserRef.window?.location.origin,
        clientId: environment.googleOAuthClientId,
        scope: 'profile email',
      });
    }
  }

  async login(email: string, password: string) {
    try {
      const body = { email: email, password: password };
      const response = await lastValueFrom(
        this.http.post<AuthResponseData>(
          `${environment.urlApi}/users/login`,
          body,
        ),
      );

      this.setUserSession(response);
    } catch {
      /* intentional */
    }
  }

  async setUserSession(response: AuthResponseData) {
    if (!isPlatformBrowser(this.platformId)) return;

    await this.storage.setObject('trokai_auth', {
      _id: response.user._id,
      email: response.user.email,
      token: response.token,
      name: response.user.name,
      avatar: response.user.avatar,
    });

    const user = new User({ ...response.user });
    user.token = response.token;

    this._user.next(user);
    this._logged.next(true);
  }

  // Synchronous on purpose: consumed by the (sync) HTTP interceptor short-circuit
  // and the route guard. localStorage is sync on the browser; StorageService is
  // async, so this single read stays on BrowserRef.
  checkStorageSession() {
    const data = this.browserRef.localStorage?.getItem('trokai_auth');
    if (data) return JSON.parse(data);
  }

  checkLogged() {
    return !!this.getUserValue();
  }

  async askToLogin() {
    const login = await this.alert.question(
      'Faça login ou crie uma conta para aproveitar todos os recursos do Trokaí',
      'Entre no Trokaí',
      'Entrar agora',
      'Agora não',
    );

    if (login) this.redirectToLogin();
  }

  logout() {
    void this.storage.clear();
    this._user.next(undefined);
    this._logged.next(false);
    this.hasPassword = null;
    this.oAuthService.logOut();
  }

  // google
  async startGoogle() {
    try {
      await this.oAuthService.loadDiscoveryDocument();
      await this.oAuthService.tryLoginImplicitFlow();

      if (!this.oAuthService.hasValidAccessToken())
        this.oAuthService.initLoginFlow();
      else {
        await this.oAuthService.loadUserProfile();
      }
    } catch {
      /* intentional */
    }
  }

  async checkGoogleLogged() {
    try {
      await this.oAuthService.loadDiscoveryDocument();
      await this.oAuthService.tryLoginImplicitFlow();

      if (!this.oAuthService.hasValidAccessToken()) return;

      const gUser: any = await this.oAuthService.loadUserProfile();

      this.googleAuth(gUser.info);
    } catch {
      /* intentional */
    }
  }

  private async googleAuth(gUser: unknown) {
    try {
      const response: any = await lastValueFrom(
        this.http.post<AuthResponseData>(environment.urlApi + '/users/google', {
          gUser,
        }),
      );
      this.setUserSession(response);
    } catch {
      /* intentional */
    }
  }

  private async appleAuth(appleUser: unknown) {
    try {
      const response: any = await lastValueFrom(
        this.http.post<AuthResponseData>(environment.urlApi + '/users/apple', {
          appleUser,
        }),
      );
      this.setUserSession(response);
    } catch {
      /* intentional */
    }
  }

  async startApple() {
    try {
      this.browserRef.loadAppleSignIn();

      // setting a small delay to ensure the script is loaded
      // worst case, user will have to click again and it will be loaded by then
      await new Promise((resolve) => setTimeout(resolve, 500));

      await AppleID.auth.init({
        clientId: environment.appleClientId,
        scope: 'name email',
        redirectURI: environment.appleRedirectUri,
        // state: '[STATE]',
        // nonce: '[NONCE]',
        usePopup: true,
      });

      const data: AppleResponse = await AppleID.auth.signIn();
      const jwtParsed: any = this.parseJwt(data.authorization.id_token);

      const appleUser = {
        // always
        authorizationCode: data.authorization.code,
        identityToken: data.authorization.id_token,
        appleId: jwtParsed.sub,

        // first time
        email: data.user?.email,
        givenName: data.user?.name?.firstName,
        familyName: data.user?.name?.lastName,
      };

      this.appleAuth(appleUser);
    } catch {
      /* intentional */
    }
  }

  async userHasPassword() {
    this.hasPassword = await this.userService.userHasPassword();
    return this.hasPassword;
  }

  async autoLogin() {
    try {
      if (!isPlatformBrowser(this.platformId)) return;

      const stored = await this.storage.get('trokai_auth');

      if (!stored) {
        this.checkGoogleLogged();
        return;
      }

      const session = JSON.parse(stored) as AuthSessionData;

      let aux: any = new User();
      aux = { ...session };

      this._user.next(aux);
      const user = await this.userService.getUserInfo();

      await this.setUserSession({ user: user, token: session.token });
    } catch (err) {
      if (!environment.production) console.log(err);
    }
  }

  async register(name: string, email: string, password: string) {
    try {
      const response = await this.userService.register(name, email, password);
      this.setUserSession(response);
    } catch {
      /* intentional */
    }
  }

  isLogged() {
    return this._logged.getValue();
  }

  getUserValue() {
    return this._user.getValue();
  }

  async updateAddress(address: Partial<Address>) {
    const payload = { ...address, country: 'BRA' };
    await this.updateUser({ address: payload });
    this.addressUpdated$.next();
  }

  async updateUser(user: Partial<User> | Record<string, unknown>) {
    const res = await this.userService.updateUser(user);
    await this.syncUserData();
    return res;
  }

  async syncUserData() {
    try {
      const updatedUser = await this.userService.getUserInfo();
      const current = this._user.getValue();
      if (current) updatedUser.token = current.token;

      this._user.next(updatedUser);
    } catch {
      /* intentional */
    }
  }

  async uploadAvatar(image: Blob) {
    const res = await this.userService.uploadAvatar(image);
    this.syncAvatar(res.imageName);
    return res;
  }

  redirectToLogin() {
    this.router.navigateByUrl('/auth/login');
  }

  syncAvatar(avatar: string) {
    const u = this.getUserValue();
    if (!u) return;
    u.avatar = avatar;
    this._user.next(u);
  }

  deleteAccount() {
    return this.userService.deleteAccount(this._user.getValue()?._id ?? '');
  }

  // apple token
  parseJwt(token: string) {
    const base64Url = token.split('.')[1];
    const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
    const jsonPayload = decodeURIComponent(
      atob(base64)
        .split('')
        .map(function (c) {
          return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
        })
        .join(''),
    );

    return JSON.parse(jsonPayload);
  }
}

import { User } from '@trokai/shared-core';
import { Component, inject, OnInit } from '@angular/core';

import { MatRadioModule } from '@angular/material/radio';
import { MatButtonModule } from '@angular/material/button';
import {
  AddressOption,
  BuyingService,
  CheckoutLocal,
} from '@trokai/shared-data-access';
import { AuthService } from 'src/app/auth/auth.service';
import { FormsModule } from '@angular/forms';
import { NgxMaskPipe } from 'ngx-mask';
import { takeUntil } from 'rxjs';
import { AutoUnsubscribe } from 'src/app/autounsubscribe';

@Component({
  selector: 'app-shipping-options',
  standalone: true,
  imports: [MatRadioModule, MatButtonModule, FormsModule, NgxMaskPipe],
  templateUrl: './shipping-options.component.html',
  styleUrl: './shipping-options.component.scss',
})
export class ShippingOptionsComponent
  extends AutoUnsubscribe
  implements OnInit
{
  private buyingService = inject(BuyingService);
  private authService = inject(AuthService);

  shipping = false;
  inPerson = false;

  checkout!: CheckoutLocal;
  user!: User;

  selectedOption?: AddressOption;
  shippingOptions = AddressOption;

  ngOnInit() {
    this.buyingService.checkoutLocal$
      .pipe(takeUntil(this.destroySignal))
      .subscribe((checkout) => {
        if (!checkout) return;

        this.checkout = checkout;

        // checkout.owner.inPerson = true; // TODO: remove this line

        this.shipping = checkout.owner.shipping;
        this.inPerson = checkout.owner.inPerson;

        if (this.inPerson && !this.shipping)
          // only inPerson
          this.selectedOption = AddressOption.INPERSON;

        if (this.shipping && !this.inPerson)
          // only shipping
          this.selectedOption = AddressOption.SHIPPING;
      });

    this.authService.user
      .pipe(takeUntil(this.destroySignal))
      .subscribe((user) => {
        if (!user) return;
        this.user = user;
      });
  }

  onChangeAddress(event: any) {
    event.stopPropagation();
    this.buyingService.goToAddAddress();
  }

  async onContinue() {
    if (this.selectedOption == null) return;
    this.checkout.shippingOption = this.selectedOption;
    this.buyingService.setCheckoutLocal(this.checkout);
    await this.buyingService.navigateCheckout();
  }
}

import { Injectable, inject } from '@angular/core';
import { Router } from '@angular/router';
import { NavigationManager, NavOptions, User } from '@trokai/shared-core';
import { AuthService } from '../auth/auth.service';

/** Web implementation of NavigationManager — Angular Router + browser history. */
@Injectable()
export class WebNavigationManager extends NavigationManager {
  private router = inject(Router);
  private auth = inject(AuthService);

  ensureAuthenticated(): boolean {
    if (this.auth.checkLogged()) return true;
    this.auth.askToLogin();
    return false;
  }

  isAuthenticated(): boolean {
    return this.auth.checkLogged();
  }

  currentUserId(): string | undefined {
    return this.auth.getUserValue()?._id;
  }

  currentUser(): User | undefined | null {
    return this.auth.getUserValue();
  }

  async syncUserData(): Promise<void> {
    await this.auth.syncUserData();
  }

  forward(commands: unknown[], opts?: NavOptions): Promise<boolean> {
    return this.router.navigate(commands as any[], {
      queryParams: opts?.queryParams,
      replaceUrl: opts?.replaceUrl,
    });
  }

  async back(): Promise<void> {
    history.back();
  }

  root(commands: unknown[], opts?: NavOptions): Promise<boolean> {
    return this.router.navigate(commands as any[], {
      queryParams: opts?.queryParams,
      replaceUrl: true,
    });
  }

  registerHardwareBack(): void {
    // No hardware back button on the web.
  }
}

import { Component, Input } from '@angular/core';
import { TkProductCardComponent } from '@trokai/shared-ui';
import { RouterLink } from '@angular/router';
import { NgOptimizedImage } from '@angular/common';

@Component({
  selector: 'app-home-generic',
  templateUrl: './home-generic.component.html',
  styleUrls: ['./home-generic.component.scss'],
  standalone: true,
  imports: [RouterLink, TkProductCardComponent, NgOptimizedImage],
})
export class HomeGenericComponent {
  @Input() home_generic: any;
  @Input() home_row: any;
  @Input() childClass!: string;
  @Input() viewportHeight!: number;
}

import {
  HttpEvent,
  HttpRequest,
  HttpResponse,
  HttpErrorResponse,
} from '@angular/common/http';
import { Observable, of } from 'rxjs';
import { Injectable, PLATFORM_ID, inject } from '@angular/core';
import { isPlatformBrowser, isPlatformServer } from '@angular/common';
import { BaseAuthInterceptor } from '@trokai/shared-core';
import { AuthService } from 'src/app/auth/auth.service';
import { AlertService } from '@trokai/shared-ui';
import { REQUEST } from './express.tokens';
import { Request } from 'express';

interface CacheEntry {
  response: HttpResponse<any>;
  expiry: number;
}

// In-memory cache store (outside the class, so it's a true singleton across interceptor instances)
const requestCache = new Map<string, CacheEntry>();
const DEFAULT_CACHE_DURATION_MS = 5 * 60 * 1000; // 5 minutes

@Injectable({ providedIn: 'root' })
export class CustomHttpInterceptor extends BaseAuthInterceptor {
  protected override readonly authScheme = 'Bearer ';

  private alertService = inject(AlertService);
  private authService = inject(AuthService);
  private platformId = inject(PLATFORM_ID);
  private request = inject<Request>(REQUEST, { optional: true });

  protected token(): string | undefined {
    return this.authService.getUserValue()?.token;
  }

  protected override shortCircuit(
    request: HttpRequest<unknown>,
  ): Observable<HttpEvent<unknown>> | null {
    // Session torn out from under the in-memory user → force logout.
    const user = this.authService.getUserValue();
    if (user?.token && !this.authService.checkStorageSession()?.token) {
      this.authService.logout();
      return of(null as unknown as HttpEvent<unknown>);
    }

    // Serve a fresh cached GET response.
    if (
      isPlatformBrowser(this.platformId) &&
      request.method === 'GET' &&
      request.headers.get('CacheEnabled')
    ) {
      const cached = requestCache.get(request.urlWithParams);
      if (cached) {
        if (Date.now() < cached.expiry) return of(cached.response.clone());
        requestCache.delete(request.urlWithParams);
      }
    }
    return null;
  }

  protected override prepare(
    request: HttpRequest<unknown>,
  ): HttpRequest<unknown> {
    if (this.isExternalApi(request.url)) return request;

    let headers = request.headers;

    // Forward real client IP during SSR so the API sees it.
    if (isPlatformServer(this.platformId) && this.request) {
      const forwardedFor = this.request.headers['x-forwarded-for'];
      const clientIp =
        typeof forwardedFor === 'string'
          ? forwardedFor.split(',')[0].trim()
          : this.request.socket?.remoteAddress;
      if (clientIp) headers = headers.append('X-Forwarded-For', clientIp);
    }

    // Ask the backend for resolved image URLs (images[].sm/md/lg).
    return request.clone({
      headers,
      params: request.params.set('resolveImages', 'true'),
    });
  }

  protected override onResponse(
    event: HttpEvent<unknown>,
    request: HttpRequest<unknown>,
  ): void {
    if (
      event instanceof HttpResponse &&
      isPlatformBrowser(this.platformId) &&
      request.method === 'GET' &&
      request.headers.get('CacheEnabled')
    ) {
      requestCache.set(request.urlWithParams, {
        response: event.clone(),
        expiry: Date.now() + DEFAULT_CACHE_DURATION_MS,
      });
    }
  }

  protected onErrorCode(code: string, _error: HttpErrorResponse): void {
    if (code === 'banned') {
      this.alertService.alert('Conta banida');
      this.authService.logout();
    } else if (code === 'token_expired') {
      this.authService.logout();
    } else if (code === 'apple_deleted') {
      this.authService.logout();
      this.alertService.alert('Conta excluída');
    } else if (code === 'apple_token') {
      this.authService.logout();
      this.alertService.alert('Sessão expirada');
    }
  }

  protected showError(message: string | null): void {
    if (message && message.toString().length > 0) {
      this.alertService.alert(message);
    } else {
      this.alertService.errorDefault();
    }
  }
}

