  imgMatrix = '';
  imgBarrasCep = '';
  imgBarrasPlp = '';
  imgBarrasEncomenda = '';

  done = false;
  printing = false;

  async ngOnInit() {
    this.title.setTitle('Etiqueta Correios | Trokaí');
    try {
      if (!isPlatformBrowser(this.platformId)) return;

      const id = this.route.snapshot.params['order_id'];

      if (!id) {
        this.router.navigateByUrl('/');
        return;
      }

      this.etiqueta = await (
        await lastValueFrom(
          this.http.post<{ etiqueta: Etiqueta }>(
            environment.urlApi + '/payments/orders/postage-label/v2/',
            { orderId: id },
          ),
        )
      ).etiqueta;

      this.calculos();
      await this.imagens();

      this.done = true;
    } catch {
      /* intentional */
    }
  }

  getMainAddrLine(address: any) {
    if (address.complement)
      return `${address.street} ${address.number}, ${address.complement}`;
    return `${address.street} ${address.number}`;
  }

  calculos() {
    const pesoTotal = this.etiqueta.order.products
      .map((item) => item.weight)
      .reduce((total, item) => total + item);

    this.pesoTotalG = (pesoTotal * 1000)
      .toFixed(0)
      .toString()
      .replace('.', ',');

    this.pesoTotalS = pesoTotal.toFixed(1).toString().replace('.', ',') + ' kg';

    this.valorTotal = this.etiqueta.order.products
      .map((item) => item.cost)
      .reduce((total, item) => total + item);
  }

  async imagens() {
    const canvas = document.createElement('canvas');

    // encomenda
    await bwipjs.toCanvas(canvas, {
      bcid: 'code128',
      text: this.etiqueta.order.codigoRastreio,
      scale: 3,
      height: 18,
      width: 80,
      textfont: 'Arial',
      textsize: 11,
      textyalign: 'above',
      includetext: true,
      textxalign: 'center',
    });

    this.imgBarrasEncomenda = canvas.toDataURL('base64');

    // matrix
    await bwipjs.toCanvas(canvas, {
      bcid: 'datamatrix',
      text: this.etiqueta.order.valorMatrix,
      scale: 3,
      height: 25,
      width: 25,
      includetext: false,
    });

    this.imgMatrix = canvas.toDataURL('base64');

    // barras CEP
    await bwipjs.toCanvas(canvas, {
      bcid: 'code128',
      text: this.etiqueta.buyer.address.zipCode,
      scale: 3,
      height: 18,
      width: 40,
      includetext: false,
    });

    this.imgBarrasCep = canvas.toDataURL('base64');

    if (
      this.etiqueta.order.plp &&
      this.etiqueta.order.plp.toString().length > 0
    ) {
      await bwipjs.toCanvas(canvas, {
        bcid: 'code128',
        text: this.etiqueta.order.plp.toString(),
        scale: 6,
        height: 6,
        width: 18,
        textfont: 'Arial',
        textsize: 5,
        textyalign: 'above',
        includetext: true,
        textxalign: 'center',
      });

      this.imgBarrasPlp = canvas.toDataURL('base64');
    }
  }

  async onSave() {
    /* intentional */
  }

  async onPrint() {
    this.printing = true;

    setTimeout(() => {
      this.browserRef.window?.print(); // imprime so no navegador
      this.printing = false;
    }, 1000); // espera a imagem carregar
  }
}

import {
  BasicModel,
  Clothes,
  ClothesStatus,
  GlobalParams,
  ItemsMap,
  UploadPictureItem,
  User,
} from '@trokai/shared-core';
import { CompletingInformationService } from 'src/app/services/completing-information.service';
import { ProductService } from '@trokai/shared-data-access';
import { Router, ActivatedRoute } from '@angular/router';
import { MatDialog } from '@angular/material/dialog';
import {
  AlertService,
  TkProductRegisterFormComponent,
} from '@trokai/shared-ui';
import { AuthService } from './../auth/auth.service';
import { InventoryService } from './../wardrobe/inventory.service';
import { GlobalService } from '../services/global.service';
import { Component, OnInit, inject } from '@angular/core';
import { PicturesHelpDialogComponent } from './pictures-help-dialog/pictures-help-dialog.component';

@Component({
  selector: 'app-product-register',
  templateUrl: './product-register.component.html',
  styleUrls: ['./product-register.component.scss'],
  standalone: true,
  imports: [TkProductRegisterFormComponent],
})
export class ProductRegisterComponent implements OnInit {
  private globalService = inject(GlobalService);
  private completingInformationService = inject(CompletingInformationService);
  private route = inject(ActivatedRoute);
  private productService = inject(ProductService);
  private authService = inject(AuthService);
  private router = inject(Router);
  private dialog = inject(MatDialog);
  private inventoryService = inject(InventoryService);
  private alertService = inject(AlertService);

  itemsMap!: ItemsMap;
  params!: GlobalParams;
  brands: BasicModel<string>[] = [];
  user!: User;

  product: Clothes | null = null;
  initialImages: UploadPictureItem[] | null = null;
  duplicating = false;
  editingId: string | null = null;
  waitingAdjustment = false;
  adjusts: string[] = [];
  adjustsNote = '';
  loading = false;

  ngOnInit(): void {
    this.globalService.setTitle('Anunciar');
    this.duplicating = this.route.snapshot.url[0]?.path === 'duplicate';

    this.globalService.itemsMap.subscribe((itemsMap) => {
      if (!itemsMap) return;
      this.itemsMap = itemsMap;
      this.checkLoadedToEdit();
    });

    this.globalService.params.subscribe((params) => {
      if (!params) return;
      this.params = params;
      this.checkLoadedToEdit();
    });

    this.globalService.brands.subscribe(() => {
      this.brands =
        this.globalService
          .getBrandsValue()
          ?.map((b) => new BasicModel<string>(b.slug, b.name)) ?? [];
    });

    this.authService.user.subscribe((u) => {
      if (u) this.user = u;
    });
  }

  async checkLoadedToEdit() {
    try {
      if (!this.params || !this.itemsMap) return;

      this.editingId = this.route.snapshot.params['product_id'];

      if (this.editingId) {
        if (await this.completingInformationService.canRegisterProduct())
          this.loadForEdit();
      } else {
        this.initialImages = [];
        await this.completingInformationService.canRegisterProduct();
      }
    } catch {
      /* intentional */
    }
  }

  async loadForEdit() {
    try {
      if (!this.editingId) return;
      const res = await this.productService.fetchProduct(this.editingId);
      const clothes = res.clothes;

      if (clothes.owner !== this.user._id) {
        this.router.navigateByUrl('/');
        return;
      }

      if (this.duplicating) {
        // Pre-fetch images as blobs so the form shows them as new local pictures.
        await this.inventoryService.startDuplicate(clothes);
      } else {
        this.inventoryService.startEditing(clothes);
      }

      this.initialImages = [...this.inventoryService.pendingPictures];

      this.waitingAdjustment =
        clothes.status === ClothesStatus.WAITING_ADJUSTMENT;

      if (this.waitingAdjustment) await this.loadReview(clothes);

      this.product = clothes;
    } catch {
      /* intentional */
    }
  }

  async loadReview(clothes: Clothes) {
    try {
      const itemReview: any = await this.inventoryService.getItemReview();
      this.adjusts = clothes.adjusts.map(
        (el) =>
          itemReview.find((ir: { _id: number; info: string }) => ir._id == el)
            .info,
      );
      this.adjustsNote = clothes.adjustsNote;
    } catch {
      /* intentional */
    }
  }

  onHelpPictures() {
    this.dialog.open(PicturesHelpDialogComponent, {
      panelClass: 'dialog-product-tips',
    });
  }

  async onSubmitted({
    clothes,
    images,
  }: {
    clothes: Clothes;
    images: UploadPictureItem[];
  }) {
    this.loading = true;
    this.inventoryService.pendingPictures = images;
    this.inventoryService.item = clothes;

    try {
      if (this.duplicating) {
        this.inventoryService.item.copyOf = clothes._id;
        delete this.inventoryService.item._id;
        await this.inventoryService.duplicate();
      } else {
        await this.inventoryService.upload();
      }

      this.router.navigateByUrl(`/users/${this.user.nickname}`, {
        replaceUrl: true,
      });

      this.alertService.alert('Anúncio enviado!');
    } catch {
      this.loading = false;
    }
  }
}

import { BasicModel, Filters, notNullOrEmpty } from '@trokai/shared-core';
import {
  AfterViewInit,
  Component,
  EventEmitter,
  Input,
  NgZone,
  OnChanges,
  OnDestroy,
  OnInit,
  Output,
  inject,
} from '@angular/core';
import { GlobalService } from 'src/app/services/global.service';
import { ItemsMap, CategoryModel } from 'src/app/models/items-map';

import { MatSelectModule } from '@angular/material/select';
import { MatInputModule } from '@angular/material/input';
import { MatRadioModule } from '@angular/material/radio';
import { MatCheckboxModule } from '@angular/material/checkbox';
import { NgClass, TitleCasePipe } from '@angular/common';
import { MatOptionModule } from '@angular/material/core';
import { FormsModule } from '@angular/forms';
import { MatFormFieldModule } from '@angular/material/form-field';
import { Subscription } from 'rxjs';
import { MatIconModule } from '@angular/material/icon';
import { MatButtonModule } from '@angular/material/button';

@Component({
  selector: 'app-search-filter',
  templateUrl: './search-filter.component.html',
  styleUrls: ['./search-filter.component.scss'],
  standalone: true,
  imports: [
    MatFormFieldModule,
    MatInputModule,
    MatSelectModule,
    FormsModule,
    MatOptionModule,
    MatCheckboxModule,
    MatRadioModule,
    NgClass,
    MatInputModule,
    TitleCasePipe,
    MatIconModule,
    MatButtonModule,
  ],
})
export class SearchFilterComponent
  implements OnInit, AfterViewInit, OnDestroy, OnChanges
{
  itemsMap: ItemsMap | null = null;
  sizes: any = [];
  pieces: any = [];

  @Input() filter = new Filters();
  @Input() enableSorting = true;
  @Input() dismissable = false;
  @Input() hideTitle = false;
  @Output() filtersChange = new EventEmitter<Filters>();
  @Output() dismiss = new EventEmitter<void>();

  sections: Record<string, boolean> = {
    condition: false,
    gender: false,
    category: false,
    size: false,
    cost: false,
    promotional: false,
  };

  category: CategoryModel | undefined;
  maxCost = 21000;
  minCost = 0;
  costRange: { lower: number | null; upper: number | null } = {
    lower: null,
    upper: null,
  };

  itemsMapSub!: Subscription;

  private globalService = inject(GlobalService);
  private ngZone = inject(NgZone);

  ngOnInit() {
    this.itemsMapSub = this.globalService.itemsMap.subscribe((itemsMap) => {
      if (itemsMap) {
        this.itemsMap = itemsMap;
        this.resetLocalFilter();
      }
    });
  }

  ngAfterViewInit(): void {
    // Run outside zone — this setTimeout creates a Zone.js macrotask that
    // keeps the app unstable until it fires.
    this.ngZone.runOutsideAngular(() => {
      setTimeout(() => {
        this.ngZone.run(() => {
          if (this.filter.costLower)
            this.costRange.lower = this.filter.costLower / 100;
          if (this.filter.costUpper)
            this.costRange.upper = this.filter.costUpper / 100;

          this.openSections();
        });
      });
    });
  }

  openSections() {
    for (const key of Object.keys(this.sections)) {
      switch (key) {
        case 'size': {
          if (notNullOrEmpty(this.filter[key]) || this.filter.age != null)
            this.sections[key] = true;
          break;
        }

        case 'piece': {
          if (notNullOrEmpty(this.filter[key])) this.sections[key] = true;
          break;
        }

        case 'cost': {
          if (this.filter.costLower != null || this.filter.costUpper != null)
            this.sections[key] = true;
          break;
        }

        default: {
          if (notNullOrEmpty(this.filter[key])) this.sections[key] = true;
        }
      }
    }
  }

  mountSizes(ageSelected: number) {
    if (ageSelected !== this.filter.age) {
      this.filter.size = [];
      this.filter.age = ageSelected;
    }

    this.sizes = [];

    if (!this.category?.['sizes'] || this.category['sizes'].length === 0)
      return;

    const ageSizes = this.category['sizes'][ageSelected];
    ageSizes.forEach((size) =>
      this.sizes.push({ sizeId: size._id, sizeValue: size.value }),
    );

    this.sizes = [...this.category['sizes'][ageSelected]];
  }

  mountPieces() {
    if (this.category)
      this.pieces = [...this.category['pieces']].sort((a, b) =>
        a.value > b.value ? 1 : -1,
      );
    else this.pieces = [];
  }

  filtersOn() {
    return this.filter.enabled();
  }

  clear() {
    this.filter = new Filters();
    this.filtersChanged();
    this.close();
  }

  changeCategory(catId: number) {
    if (catId == null) return;
    const cat = this.itemsMap?.category.find((item) => item._id === catId);

    if (cat) this.selectCategory(catId);
  }

  selectAge() {
    this.filter.size = [];
    this.filtersChanged();
    if (this.filter.age != null) this.mountSizes(this.filter.age);
  }

  selectCategory(catId: number) {
    const cat = this.itemsMap?.category.find((c) => c._id === catId);
    if (!cat) return;

    if (this.category && this.category['_id'] == cat._id) {
      this.category = undefined;
      this.filter.category = undefined;
      this.filter.age = undefined;
    } else {
      this.category = { ...cat };
      this.filter.category = cat._id;
    }

    this.sizes = [];
    this.filter.size = [];
    this.filter.piece = [];

    if (this.filter.age != null) this.mountSizes(this.filter.age);

    this.mountPieces();

    this.filtersChanged();
  }

  private multipleSelected(property: string, item: BasicModel) {
    if (!notNullOrEmpty(this.filter[property])) return false;

    if (Array.isArray(this.filter[property])) {
      return this.filter[property].find((el) => el === item._id) != null;
    } else {
      return this.filter[property] === item._id;
    }
  }

  select(property: string, item?: BasicModel) {
    if (Filters.booleanFilters.includes(property)) {
      if (!this.filter[property]) this.filter[property] = true;
      else delete this.filter[property];

      this.filtersChanged();
      return;
    }

    if (!item) return;

    if (Filters.singleChoiceFilters.includes(property))
      this.selectSingle(property, item);
    else this.selectMultiple(property, item);
  }

  selected(property: string, item: BasicModel) {
    if (Filters.singleChoiceFilters.includes(property))
      return this.filter[property] === item._id;
    else return this.multipleSelected(property, item);
  }

  selectMultiple(property: string, item: BasicModel) {
    const index = this.filter[property].findIndex(
      (el: number | string) => el.toString() === item._id.toString(),
    );

    if (index >= 0) {
      this.filter[property].splice(index, 1);
    } else {
      const els = [...this.filter[property]];
      els.push(item._id);
      this.filter[property] = els;
    }
    this.filtersChanged();
  }

  // special, gender, condition
  selectSingle(property: string, item: BasicModel) {
    if (this.filter[property] == null) this.filter[property] = item._id;
    else if (this.filter[property] === item._id) this.filter[property] = null;
    else this.filter[property] = item._id;

    this.filtersChanged();
  }

  changeCost() {
    const _lower = this.filter.costLower;
    const _upper = this.filter.costUpper;

    let invalid = false;

    if (this.sections.cost) {
      const lower = this.costRange.lower;
      const upper = this.costRange.upper;

      if (
        lower != null &&
        (lower > this.maxCost ||
          lower < this.minCost ||
          (upper != null && lower > upper))
      ) {
        invalid = true;
      } else if (lower != null) {
        this.filter.costLower = lower * 100;
      }

      if (
        upper != null &&
        (upper > this.maxCost ||
          upper < this.minCost ||
          (lower != null && lower > upper))
      ) {
        invalid = true;
      } else if (upper != null) {
        this.filter.costUpper = upper * 100;
      }
    } else {
      this.filter.costLower = undefined;
      this.filter.costUpper = undefined;
    }

    if (
      (!invalid && _lower != this.filter.costLower) ||
      _upper != this.filter.costUpper
    )
      this.filtersChanged();
  }

  changeSorting() {
    this.filtersChanged();
  }

  async filtersChanged() {
    setTimeout(() => {
      const filter = new Filters({ ...this.filter });
      this.filtersChange.emit(filter);
    }, 100);
  }

  // sections checking
  checkSectionGender() {
    if (this.sections.gender) return;
    this.filter.gender = [];
    this.filtersChanged();
  }

  checkSectionSize() {
    this.filter['size'] = [];
    if (!this.sections.size) {
      this.filter.age = undefined;
      this.sizes = [];
      this.filtersChanged();
    }
  }

  checkSectionCondition() {
    if (this.sections.condition) return;
    this.filter.condition = [];
    this.filtersChanged();
  }

  checkSectionCost() {
    if (this.sections.cost) return;
    this.filter.costLower = undefined;
    this.filter.costUpper = undefined;
    this.costRange.lower = null;
    this.costRange.upper = null;
    this.filtersChanged();
  }

  checkSectionCategory() {
    if (this.sections.category) return;

    this.sizes = [];
    this.category = undefined;
    this.sections.size = false;

    this.filter.size = [];
    this.filter.age = undefined;
    this.filter.category = undefined;
    this.filter.piece = [];

    this.filtersChanged();
  }

  resetLocalFilter() {
    if (!this.filter.size) this.filter.size = [];
    if (!this.filter.piece) this.filter.piece = [];
    if (!this.filter.gender) this.filter.gender = [];
    if (!this.filter.condition) this.filter.condition = [];

    if (this.filter.category != null) {
      const cat = this.itemsMap?.category.find(
        (c) => c._id === this.filter.category,
      );
      if (cat) {
        this.category = { ...cat };
        this.mountPieces();
      }
      if (this.filter.age != null) this.mountSizes(this.filter.age);
    }

    this.openSections();
  }

  ngOnChanges(): void {
    this.openSections();

    if (
      !this.itemsMap ||
      (this.filter.category == null && this.category == null)
    )
      return;

    if (this.filter.category !== this.category?._id) {
      this.category = this.itemsMap.category.find(
        (cat) => cat._id === this.filter.category,
      );
      this.mountPieces();
      this.sizes = [];
    }
  }

  close() {
    this.dismiss.emit();
  }

  ngOnDestroy(): void {
    if (this.itemsMapSub) this.itemsMapSub.unsubscribe();
  }
}

import {
  Component,
  DestroyRef,
  OnDestroy,
  OnInit,
  ViewChild,
  inject,
} from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { GlobalService } from '../services/global.service';
import { Paginator, PaginatorComponent } from './paginator/paginator.component';
import { SearchService } from './search.service';
import { ItemsMap } from '../models/items-map';

import { TkProductCardComponent } from '@trokai/shared-ui';
import { MatBadgeModule } from '@angular/material/badge';
import { FormsModule } from '@angular/forms';
import { SearchFilterComponent } from './search-filter/search-filter.component';
import { MatIconModule } from '@angular/material/icon';
import { MatButtonModule } from '@angular/material/button';
import { Clothes, Filters } from '@trokai/shared-core';
import { SearchPageService } from '../services/search-page.service';
import { MatDialog } from '@angular/material/dialog';
import { FilterDialogComponent } from './filter-dialog/filter-dialog.component';
import { first, lastValueFrom } from 'rxjs';
import { MatSelectModule } from '@angular/material/select';
import { MatFormFieldModule } from '@angular/material/form-field';
import { SortingDialogComponent } from './sorting-dialog/sorting-dialog.component';
import { MarketingService } from '../services/marketing.service';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

@Component({
  selector: 'app-search',
  templateUrl: './search.component.html',
  styleUrls: ['./search.component.scss'],
  standalone: true,
  imports: [
    MatButtonModule,
    MatIconModule,
    SearchFilterComponent,
    FormsModule,
    MatBadgeModule,
    TkProductCardComponent,
    PaginatorComponent,
    MatSelectModule,
    MatFormFieldModule,
  ],
})
export class SearchComponent implements OnInit, OnDestroy {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private searchService = inject(SearchService);
  private searchPageService = inject(SearchPageService);
  private globalService = inject(GlobalService);
  private marketingService = inject(MarketingService);
  private matDialog = inject(MatDialog);
  private destroyRef = inject(DestroyRef);

  results: Clothes[] = [];
  filters: Filters = new Filters();
  itemsMap?: ItemsMap;

  paginator!: Paginator;
  activePage = 0;

  countString: string | null = null;
  pageString: string | null = null;

  limit = 60;
  mobileSearchText = '';

  @ViewChild(PaginatorComponent) paginatorComponent!: PaginatorComponent;

  ngOnInit(): void {
    this.route.queryParams
      .pipe(takeUntilDestroyed(this.destroyRef)) // Inject DestroyRef in constructor
      .subscribe((params: any) => {
        this.processParams({ ...params });
      });

    // For the global items map, if you only need it once for the render:
    this.globalService.itemsMap
      .pipe(first((res) => !!res)) // Only take the first valid value
      .subscribe((res) => {
        this.itemsMap = res;
      });

    if (this.route.snapshot.queryParams['coupon']) {
      this.marketingService.checkCoupon(
        this.route.snapshot.queryParams['coupon'],
      );
      return;
    }
  }

  async processParams(params: { [key: string]: any }) {
    this.setMeta(params);

    if (params.page) {
      this.activePage = parseInt(params.page);
      if (this.activePage > 0) this.activePage--;
    }

    // page
    this.filters = new Filters(params);
    this.mobileSearchText = this.filters.text ?? '';
    this.searchPageService.setMainSearchText(this.filters.text ?? '');
    this.searchClothes();
  }

  setMeta(params: { [key: string]: any } = {}) {
    this.globalService.setTitle(params.text ?? 'Busca');
    if (params && params.text) {
      this.globalService.setMetaDescription(
        `${params.text} e outros diversos produtos no Trokaí. Compre ou venda roupas e acessórios.`,
      );
    } else {
      this.globalService.setMetaDescription(
        'Compre dos melhores brechós com segurança e praticidade.',
      );
    }
  }

  async sortingChanged(ev: { value: string }) {
    this.applyFilters({ ...this.filters, sorting: ev.value } as Filters);
  }

  searchText() {
    this.applyFilters({
      ...this.filters,
      text: this.mobileSearchText,
    } as Filters);
  }

  mountCountString(current: number, total: number) {
    this.countString = null;
    this.pageString = null;

    if (current == 0) {
      this.countString = 'Nenhum resultado ';
      return;
    }
    if (current == 1) {
      this.countString = '1 resultado ';
      return;
    }

    if (current == total) {
      this.countString = `${total} resultados `;
      return;
    }

    // total should be ex: 16 mil instead of 16000

    const totalStr =
      total < 1000 ? total.toString() : `${Math.floor(total / 1000)} mil`;

    this.countString = `${current} de ${totalStr} resultados `;

    const pages = Math.ceil(total / this.limit);
    if (pages == 1) return;

    this.pageString = `Página ${this.activePage + 1} de ${pages}`;
  }

  applyFilters(filters: Filters) {
    filters = new Filters({ ...filters });

    this.router.navigate(['/search'], {
      queryParams: { ...filters.getUrlParams(), page: 1 },
    });
  }

  async showFiltersDialog() {
    const dialogRef = this.matDialog.open(FilterDialogComponent, {
      data: { filter: this.filters },
      panelClass: 'dialog-large',
    });

    const result = await lastValueFrom(dialogRef.afterClosed());
    if (result?.filter) this.applyFilters(result.filter);
  }

  async showSortingDialog() {
    const dialogRef = this.matDialog.open(SortingDialogComponent, {
      data: { sorting: this.filters.sorting },
      panelClass: 'dialog-large',
    });

    const result = await lastValueFrom(dialogRef.afterClosed());
    if (result?.sorting) {
      this.applyFilters({
        ...this.filters,
        sorting: result.sorting,
      } as Filters);
    }
  }

  getSortingString() {
    if (this.filters.sorting == 'cost') return 'Mais baratos';
    if (this.filters.sorting == 'recent') return 'Mais recentes';
    return 'Em destaque';
  }

  async searchClothes() {
    const filters = { ...this.filters };

    try {
      const response = await this.searchService.getClothes(
        filters as Filters,
        this.limit * this.activePage,
        this.limit,
      );

      if (response) {
        if (!this.results) this.results = [];
        this.results = response.clothes;
        this.mountCountString(response.clothes.length, response.count);

        this.paginator = new Paginator(
          this.activePage + 1,
          response.count / this.limit,
        );
      }
    } finally {
      /* intentional */
    }
  }

  ngOnDestroy() {
    // Wrap this so it doesn't interrupt the navigation's stability
    if (typeof requestAnimationFrame !== 'undefined') {
      requestAnimationFrame(() => {
        this.searchPageService.setMainSearchText('');
      });
    } else {
      this.searchPageService.setMainSearchText('');
    }
  }
}

import { User } from '@trokai/shared-core';
import { Clothes } from '@trokai/shared-core';
import { HttpClient } from '@angular/common/http';
import { Injectable, inject } from '@angular/core';
import { lastValueFrom, map } from 'rxjs';
import {
  CollectionResponse,
  Filters,
  SearchResponse,
  UserSearchResponse,
} from '@trokai/shared-core';
import { GeolocationService } from '../services/geolocation.service';
import { environment } from '../../environments/environment';

@Injectable({
  providedIn: 'root',
})
export class SearchService {
  private http = inject(HttpClient);
  private locationService = inject(GeolocationService);

  async getUserInfo(userIdOrNick: string) {
    const res = await lastValueFrom(
      this.http.get<User>(environment.urlApi + '/users/' + userIdOrNick, {
        headers: { CacheEnabled: 'true' }, // Custom header to enable caching
      }),
    );

    console.log('User info response:', res); // Log the raw response for debugging

    return new User(res);
  }

  /**
   *
   * @param userId product owner id
   * @param skip
   * @param limit
   * @param filter filter to apply
   * @param excludeIds products ids to exclude
   * @returns
   */
  getClothesOfUser(
    userId: string,
    skip: number,
    limit: number,
    filter?: Filters,
    exclude: string[] = [],
    cache = false,
  ) {
    return lastValueFrom(
      this.http.get<SearchResponse>(
        environment.urlApi + '/products/users/' + userId,
        {
          params: {
            skip,
            limit,
            ...filter,
            exclude: exclude.join(','),
          },
          headers: cache
            ? { CacheEnabled: 'true' } // Custom header to enable caching
            : {}, // Use the headers object with CacheEnabled if caching is enabled
        },
      ),
    );
  }

  getClothes(
    filters: Filters,
    skip: number,
    limit: number,
  ): Promise<SearchResponse> {
    filters = new Filters(filters); // create a new instance to avoid mutating the original one

    const searchLocation = this.locationService.getSearchLocationValue();

    if (searchLocation) {
      filters.placeLat = searchLocation.lat;
      filters.placeLng = searchLocation.lng;
    }

    if (filters.text == null) delete filters.text;

    return lastValueFrom(
      this.http.get<SearchResponse>(environment.urlApi + '/products', {
        params: {
          skip,
          limit,
          ...filters,
        },
        headers: { CacheEnabled: 'true' }, // Custom header to enable caching
      }),
    );
  }

  getUsers(skip = 0, limit = 30, text = '') {
    const searchLocation = this.locationService.getSearchLocationValue();

    const params: {
      skip: number;
      limit: number;
      text: string;
      placeLat?: number;
      placeLng?: number;
    } = {
      skip,
      limit,
      text,
    };

    if (searchLocation) {
      params.placeLat = searchLocation.lat;
      params.placeLng = searchLocation.lng;
    }

    return lastValueFrom(
      this.http.get<UserSearchResponse>(`${environment.urlApi}/users`, {
        params: { ...params },
      }),
    );
  }

  fetchCompleteProduct(productId: string) {
    return this.http.get<{ clothes: Clothes }>(
      `${environment.urlApi}/clothes/${productId}/details`,
    );
  }

  getUserReviews(userId: string) {
    return lastValueFrom(
      this.http
        .get<any>(environment.urlApi + '/users/' + userId + '/reviews')
        .pipe(map((item) => item['reviews'])),
    );
  }

  getCollection(slug: string, skip: number, limit: number) {
    return lastValueFrom(
      this.http.get<CollectionResponse>(
        `${environment.urlApi}/collections/${slug}`,
        {
          params: {
            skip: skip.toString(),
            limit: limit.toString(),
          },
        },
      ),
    );
  }
}

import { isPlatformBrowser } from '@angular/common';
import { Injectable, NgZone, PLATFORM_ID, inject } from '@angular/core';
import { BehaviorSubject } from 'rxjs';
import { environment } from 'src/environments/environment';

function _window(): any {
  return window;
}

function _localStorage(): any {
  return localStorage;
}

function _sessionStorage(): any {
  return sessionStorage;
}

@Injectable()
export class BrowserRef {
  private platformId = inject(PLATFORM_ID);
  private ngZone = inject(NgZone);

  private _connected = new BehaviorSubject<boolean>(true);

  constructor() {
    this.loadNet();
  }

  get window(): any {
    if (isPlatformBrowser(this.platformId)) return _window();
    return null;
  }

  get localStorage(): any {
    if (isPlatformBrowser(this.platformId)) return _localStorage();
    return null;
  }

  get sessionStorage(): any {
    if (isPlatformBrowser(this.platformId)) return _sessionStorage();
    return null;
  }

  get connected$() {
    return this._connected.asObservable();
  }

  private loadNet() {
    if (!this.window) return;
    this.ngZone.runOutsideAngular(() => {
      window.addEventListener('online', () =>
        this.ngZone.run(() => this._connected.next(true)),
      );
      window.addEventListener('offline', () =>
        this.ngZone.run(() => this._connected.next(false)),
      );
    });
  }

  public loadMainScripts() {
    if (!this.window) return;
    this.loadPixel();
    this.loadClarity();
  }

  public loadSecondaryScripts() {
    // this.loadJivo();
  }

  private async loadClarity() {
    if (!environment.production) return;
    const Clarity = (await import('@microsoft/clarity')).default;
    Clarity.init(environment.clarity);
  }

  private loadJivo() {
    if (!environment.production) return;
    if (!this.window || (window as any).jivoLoaded) return;
    const script = document.createElement('script');
    script.src = '//code.jivosite.com/widget/VvxfqN68OV';
    script.async = true;
    document.head.appendChild(script);
    (window as any).jivoLoaded = true;
  }

  private loadPixel() {
    if (!this.window || (window as any).fbqLoaded) return;
    const script = document.createElement('script');
    script.src = 'https://connect.facebook.net/en_US/fbevents.js';
    script.async = true;
    document.head.appendChild(script);
    (window as any).fbqLoaded = true;
  }

  public loadAppleSignIn() {
    if (!this.window || (window as any).appleSignInLoaded) return;
    const script = document.createElement('script');
    script.src =
      'https://appleid.cdn-apple.com/appleauth/static/jsapi/appleid/1/en_US/appleid.auth.js';
    script.async = true;
    document.head.appendChild(script);
    (window as any).appleSignInLoaded = true;
  }
}

import { Injectable, PLATFORM_ID, inject } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';
import { Request } from 'express';
import { REQUEST } from '../express.tokens';

@Injectable({
  providedIn: 'root',
})
export class CookiesService {
  private platformId = inject(PLATFORM_ID);
  private request = inject<Request>(REQUEST, { optional: true });

  private isBrowser: boolean;

  constructor() {
    this.isBrowser = isPlatformBrowser(this.platformId);
  }

  /**
   * Get a cookie value by key.
   * Returns the parsed JSON object or null if not found.
   */
  get<T>(key: string): T | null {
    const cookieString = this.getCookieString();
    const match = cookieString.match(new RegExp('(^| )' + key + '=([^;]+)'));

    if (match) {
      try {
        return JSON.parse(decodeURIComponent(match[2])) as T;
      } catch (_e) {
        return null;
      }
    }
    return null;
  }

  /**
   * Set a cookie value (Browser Only).
   * @param key The name of the cookie
   * @param value The data object to store
   * @param days Expiration in days (default: 365). Pass null for session cookie.
   */
  set(key: string, value: any, days = 365): void {
    if (!this.isBrowser) {
      return; // We typically don't set cookies from the server during rendering
    }

    const jsonValue = encodeURIComponent(JSON.stringify(value));
    let expires = '';

    if (days) {
      const date = new Date();
      date.setTime(date.getTime() + days * 24 * 60 * 60 * 1000);
      expires = `; expires=${date.toUTCString()}`;
    }

    // path=/ ensures it's available on all routes
    // SameSite=Lax is good for standard navigation
    document.cookie = `${key}=${jsonValue}${expires}; path=/; SameSite=Lax`;
  }

  /**
   * Delete a cookie by setting its expiry to the past.
   */
  delete(key: string): void {
    if (this.isBrowser) {
      document.cookie = `${key}=; path=/; expires=Thu, 01 Jan 1970 00:00:01 GMT;`;
    }
  }

  /**
   * Checks if a cookie exists.
   */
  has(key: string): boolean {
    return !!this.get(key);
  }

  private getCookieString(): string {
    if (this.isBrowser) {
      return document.cookie || '';
    } else {
      // Server-side: read from Express request
      return this.request?.headers?.cookie || '';
    }
  }
}

import { isPlatformBrowser } from '@angular/common';
import { HttpClient } from '@angular/common/http';
import { Injectable, PLATFORM_ID, inject } from '@angular/core';
import { BehaviorSubject, lastValueFrom } from 'rxjs';
import { AuthService } from 'src/app/auth/auth.service';
import { environment } from 'src/environments/environment';
import { AlertService } from '@trokai/shared-ui';
import { BrowserRef } from './browser-ref.service';
import { CookiesService } from './cookies.service';

import { RespostaCep, SearchLocation } from '@trokai/shared-core';

@Injectable({
  providedIn: 'root',
})
export class GeolocationService {
  private http = inject(HttpClient);
  private browserRef = inject(BrowserRef);
  private alert = inject(AlertService);
  private authService = inject(AuthService);
  private cookiesService = inject(CookiesService);
  private platformId = inject(PLATFORM_ID);

  private readonly COOKIE_KEY = 'search_location';
  private readonly SEARCH_LOCATION_CHANGED = 'search_location_changed';
  private readonly BROADCAST_CHANNEL_NAME = 'search_location_update';

  private _searchLocation = new BehaviorSubject<SearchLocation | null>(null);
  private _addressChannel: BroadcastChannel | null = null;

  // Controla os enderecos disponiveis
  constructor() {
    // se o usuario alterar seu endereco
    this.authService.addressUpdated$.subscribe(() => {
      const u = this.authService.getUserValue();

      console.log('Address updated, refreshing search location', u?.address);

      if (!u?.address?.location || u.address.zipCode == null) return;

      this.setSearchLocation(
        u.address.location.coordinates[1],
        u.address.location.coordinates[0],
        u.address.zipCode,
        true,
      );
    });

    // 2. Listen for changes from other tabs (browser only)
    if (isPlatformBrowser(this.platformId)) {
      this._addressChannel = new BroadcastChannel(this.BROADCAST_CHANNEL_NAME);
      this._addressChannel.onmessage = (event) => {
        if (event.data.type === this.SEARCH_LOCATION_CHANGED) {
          const newLocation = event.data.data as SearchLocation;
          this.setSearchLocation(
            newLocation.lat,
            newLocation.lng,
            newLocation.zip,
          );
        }
      };
    }
  }

  get searchLocation() {
    return this._searchLocation.asObservable();
  }

  // private methods
  private async getLatLngFromCep(cep: number) {
    return lastValueFrom(
      this.http.get(
        `https://maps.googleapis.com/maps/api/geocode/json?address=${cep}
      &components=country:BR&key=${environment.mapsGeocodingKey}`,
      ),
    );
  }

  private async setSearchLocation(
    lat: number,
    lng: number,
    zip: number,
    broadcast = false,
  ) {
    const newLocation = new SearchLocation(lat, lng, zip);
    this._searchLocation.next(newLocation);

    this.cookiesService.set(this.COOKIE_KEY, newLocation);

    if (broadcast && this._addressChannel) {
      this._addressChannel.postMessage({
        type: this.SEARCH_LOCATION_CHANGED,
        data: newLocation,
      });
    }
  }

  private getCookieSearchLocation(): SearchLocation | null {
    return this.cookiesService.get<SearchLocation>(this.COOKIE_KEY);
  }

  // public methods
  public async init() {
    try {
      // check storage for last search location
      const sessionLocation = this.getCookieSearchLocation();

      // if there is a stored location, use it
      if (sessionLocation) {
        await this.setSearchLocation(
          sessionLocation.lat,
          sessionLocation.lng,
          sessionLocation.zip,
        );
        return;
      }

      const user = this.authService.getUserValue();

      // home address
      if (user && user.address?.location && user.address.zipCode != null) {
        const lat = user.address.location.coordinates[1];
        const lng = user.address.location.coordinates[0];
        const zip = user.address.zipCode;
        await this.setSearchLocation(lat, lng, zip);
        return;
      }
    } catch (error) {
      console.log(error);
    }
  }

  public async getAddressFromZip(
    zipCode: string | number,
  ): Promise<RespostaCep> {
    return lastValueFrom(
      this.http.get<RespostaCep>(`https://viacep.com.br/ws/${zipCode}/json/`),
    );
  }

  public async changeSearchZip(zipCode: number) {
    try {
      const res: any = await this.getLatLngFromCep(zipCode);

      if (res.results.length === 0) {
        this.alert.alert('CEP não encontrado');
        return;
      }

      const lat = res.results[0].geometry.location.lat;
      const lng = res.results[0].geometry.location.lng;

      await this.setSearchLocation(lat, lng, zipCode, true);
    } catch (error) {
      console.log(error);
    }
  }

  public getSearchLocationValue(): SearchLocation | null {
    return this._searchLocation.getValue();
  }

  public reset() {
    this._searchLocation.next(null);
    this.init();
  }
}

import { Injectable, PLATFORM_ID, inject } from '@angular/core';
import { Meta } from '@angular/platform-browser';
import { isPlatformServer } from '@angular/common';

@Injectable({
  providedIn: 'root',
})
export class PreloadService {
  private meta = inject(Meta);
  private platformId = inject<object>(PLATFORM_ID);

  preloadImage(url: string) {
    if (!isPlatformServer(this.platformId)) return;

    this.meta.addTags([
      {
        rel: 'preload',
        as: 'image',
        href: url,
        fetchpriority: 'high',
      } as any,
    ]);
  }

  preloadMobileAndDesk(mobileUrl: string, desktopUrl: string) {
    if (!isPlatformServer(this.platformId)) return;

    this.meta.addTags([
      {
        rel: 'preload',
        as: 'image',
        href: desktopUrl,
        media: '(min-width: 769px)',
        fetchpriority: 'high',
      } as any,
      {
        rel: 'preload',
        as: 'image',
        href: mobileUrl,
        media: '(max-width: 768px)',
        fetchpriority: 'high',
      } as any,
    ]);
  }
}

import { Clothes, GtmProductData } from '@trokai/shared-core';
import { isPlatformBrowser } from '@angular/common';
import { Injectable, NgZone, PLATFORM_ID, inject } from '@angular/core';
import { GoogleTagManagerService } from 'angular-google-tag-manager';
import { AuthService } from '../auth/auth.service';
import { environment } from 'src/environments/environment';

enum GtmEvents {
  USER_IDENTIFY = 'user_identify',
  USER_LOGOUT = 'user_logout',
  VIEW_PRODUCT = 'view_product',
  ADD_TO_CART = 'add_to_cart',
  BEGIN_CHECKOUT = 'begin_checkout',
  ADD_PAYMENT_INFO = 'add_payment_info',
  PURCHASE = 'purchase',
}

@Injectable({
  providedIn: 'root',
})
export class TrokaiGtmService {
  private gtmService = inject(GoogleTagManagerService);
  private authService = inject(AuthService);
  private ngZone = inject(NgZone);
  private platformId = inject(PLATFORM_ID);

  // Controle de debounce para evitar cliques duplos acidentais (500ms)
  private lastEvents: { [key: string]: number } = {};
  private readonly DEBOUNCE_TIME = 500;

  private _gtmReady = false;
  private _pendingTags: object[] = [];

  public get hasConsent() {
    return (
      isPlatformBrowser(this.platformId) &&
      !!localStorage.getItem('accepted_cookies')
    );
  }

  /**
   * Verifica se pode disparar o evento (proteção contra double-click rápido)
   */
  private canFire(eventName: string): boolean {
    if (!isPlatformBrowser(this.platformId) || !environment.production)
      return false;

    const now = Date.now();
    const lastFired = this.lastEvents[eventName] || 0;

    if (now - lastFired < this.DEBOUNCE_TIME) {
      return false;
    }

    this.lastEvents[eventName] = now;
    return true;
  }

  public addGtmToDom() {
    if (isPlatformBrowser(this.platformId)) {
      // Run the script injection outside Angular
      this.ngZone.runOutsideAngular(() => {
        this.gtmService.addGtmToDom().then(() => {
          this._gtmReady = true;
          this._pendingTags.forEach((tag) => this.pushToDataLayer(tag));
          this._pendingTags = [];
        });
      });
    }
  }

  // Helper method to push tags without blocking Angular's stability
  private pushToDataLayer(tag: object) {
    if (!isPlatformBrowser(this.platformId)) return;

    this.ngZone.runOutsideAngular(() => {
      // 1. Get the native window object
      const windowObj = window as any;

      // 2. Push directly to the array.
      // This is synchronous and bypasses the library's Promise logic entirely.
      if (windowObj.dataLayer) {
        windowObj.dataLayer.push(tag);
      } else {
        // Fallback: if dataLayer isn't init'd yet, use the library
        this.gtmService.pushTag(tag).catch(() => {
          /* intentional */
        });
      }
    });
  }

  /**
   * Chamar assim que o usuário fizer Login ou o App carregar logado.
   * Envia dados para o GA4 unir sessões e para a Meta fazer o Advanced Matching.
   */
  identifyUser() {
    if (!this.hasConsent) return;
    if (!this.canFire(GtmEvents.USER_IDENTIFY)) return;

    const userData = this.authService.getUserValue();
    if (!userData) return;

    const tag = {
      event: GtmEvents.USER_IDENTIFY,
      ...this.getUserContext(),
    };

    // Use the helper!
    // This pushes outside the zone so it won't block stability.
    this.pushToDataLayer(tag);
  }

  /**
   * Limpa os dados do usuário do DataLayer ao fazer logout.
   * Essencial para SPAs (Angular) para evitar misturar dados de usuários.
   */
  logoutEvent() {
    if (!this.hasConsent) return;
    if (!this.canFire(GtmEvents.USER_LOGOUT)) return;

    const tag = {
      event: GtmEvents.USER_LOGOUT,
      user_id: null, // Zera o ID no GA4
      user_data: null, // Zera os dados pessoais (email/phone) no Meta
    };

    // Use o helper para garantir que não bloqueie a navegação
    this.pushToDataLayer(tag);
  }

  // --- EVENTOS DE E-COMMERCE ---

  viewProductEvent(productData: Clothes) {
    if (!this.canFire(GtmEvents.VIEW_PRODUCT)) return;

    const tag = {
      event: GtmEvents.VIEW_PRODUCT,
      ecommerce: {
        items: [new GtmProductData(productData)],
        value: productData.cost / 100,
        currency: 'BRL',
      },
      ...this.getUserContext(),
    };

    if (!this._gtmReady) {
      this._pendingTags.push(tag);
      return;
    }

    // Call the helper instead of awaiting the service directly
    this.pushToDataLayer(tag);
  }

  addToCartEvent(productData: Clothes) {
    if (!this.canFire(GtmEvents.ADD_TO_CART)) return;

    const tag = {
      event: GtmEvents.ADD_TO_CART,
      ecommerce: {
        items: [new GtmProductData(productData)],
        value: productData.cost / 100,
        currency: 'BRL',
      },
      ...this.getUserContext(), // Adiciona contexto do usuário se disponível
    };

    if (!this._gtmReady) {
      this._pendingTags.push(tag);
      return;
    }

    // Call the helper instead of awaiting the service directly
    this.pushToDataLayer(tag);
  }

  beginCheckoutEvent(cartTotal: number, items: Clothes[]) {
    // Aqui não tem problema disparar múltiplas vezes se o user for e voltar
    if (!this.canFire(GtmEvents.BEGIN_CHECKOUT)) return;

    const tag = {
      event: GtmEvents.BEGIN_CHECKOUT,
      ecommerce: {
        currency: 'BRL',
        value: cartTotal / 100,
        items: items.map((item) => new GtmProductData(item)),
      },
      ...this.getUserContext(), // Adiciona contexto do usuário se disponível
    };

    if (!this._gtmReady) {
      this._pendingTags.push(tag);
      return;
    }

    // Call the helper instead of awaiting the service directly
    this.pushToDataLayer(tag);
  }

  addPaymentInfoEvent() {
    if (!this.canFire(GtmEvents.ADD_PAYMENT_INFO)) return;
    const tag = {
      event: GtmEvents.ADD_PAYMENT_INFO,
      ...this.getUserContext(),
    };
    this.pushToDataLayer(tag);
  }

  purchaseEvent(orderId: string, valueBRL: number, items: Clothes[]) {
    // Purchase é crítico, geralmente não se bloqueia, mas o debounce de 500ms
    // ajuda se o botão "Finalizar" não desabilitar rápido o suficiente na UI.
    if (!this.canFire(GtmEvents.PURCHASE)) return;

    const tag = {
      event: GtmEvents.PURCHASE,
      ecommerce: {
        transaction_id: orderId,
        value: valueBRL / 100,
        currency: 'BRL',
        items: items.map((item) => new GtmProductData(item)),
      },
      ...this.getUserContext(), // Adiciona contexto do usuário se disponível
    };

    if (!this._gtmReady) {
      this._pendingTags.push(tag);
      return;
    }

    // Call the helper instead of awaiting the service directly
    this.pushToDataLayer(tag);
  }

  private getUserContext() {
    if (!this.hasConsent) return null;

    const user = this.authService.getUserValue(); // Seu método de pegar usuário da memória
    if (!user) return null;

    return {
      user_id: user._id, // Para o GA4 (Sessão unificada)
      user_data: {
        // Para o Facebook (Advanced Matching)
        email_address: user.email,
        phone_number: `55${user.phone}`, // Opcional, mas recomendado
      },
    };
  }
}

import { environment } from 'src/environments/environment';

const DEBUG_KEY = 'trokai_debug';

function isEnabled(): boolean {
  if (!environment.production) return true;

  try {
    return (
      typeof localStorage !== 'undefined' && !!localStorage.getItem(DEBUG_KEY)
    );
  } catch {
    return false;
  }
}

function format(level: string, args: any[]): any[] {
  const time = new Date().toISOString().substring(11, 23);
  return [`[${time}] [${level}]`, ...args];
}

export const logger = {
  log: (...args: any[]) => {
    if (isEnabled()) console.log(...format('LOG', args));
  },
  warn: (...args: any[]) => {
    if (isEnabled()) console.warn(...format('WARN', args));
  },
  error: (...args: any[]) => {
    if (isEnabled()) console.error(...format('ERR', args));
  },
  group: (label: string) => {
    if (isEnabled()) console.group(`[${label}]`);
  },
  groupEnd: () => {
    if (isEnabled()) console.groupEnd();
  },
};
